INSERT INTO public.about_pages (id, document_id, kicker, title, intro, sections, created_at, updated_at, published_at, created_by_id, updated_by_id, locale) VALUES (1, 'zg3ujryicqj7apqdccqugiym', 'À propos', 'Comprendre PRETE SUBCO', 'Cette section rassemble les éléments essentiels pour situer le projet, le mécanisme de subvention et les investissements productifs ciblés.', '[{"text": "PRETE accompagne la transformation productive locale en ciblant des investissements capables de renforcer les chaînes de valeur prioritaires.", "title": "Le projet PRETE / NYUNGANIRA"}, {"text": "SUBCO organise l’information, la préparation, la soumission et le suivi des demandes de subventions de contrepartie.", "title": "Le mécanisme SUBCO"}, {"text": "Le dispositif vise des projets structurants, viables et utiles aux MPME, avec un accent sur l’emploi, l’inclusion et la compétitivité.", "title": "Objectifs du dispositif"}, {"text": "Les infrastructures productives peuvent être matérielles ou immatérielles : équipements, services, systèmes qualité, logistique, traçabilité ou appuis techniques.", "title": "Infrastructures productives"}, {"text": "La plateforme présente les partenaires impliqués dans le pilotage, l’accompagnement et la mise en œuvre du mécanisme.", "title": "Partenaires institutionnels"}]', '2026-05-08 14:28:04.66', '2026-05-08 14:28:04.66', '2026-05-08 14:28:04.66', NULL, NULL, NULL);


