INSERT INTO public.call_for_proposals (id, document_id, title, slug, summary, content, opening_date, deadline_date, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, call_status) VALUES (1, 'fh8c7pz831cv6759ji2a8skl', 'Appel à propositions - Cohorte 1', 'appel-cohorte-1', 'Appel pilote pour les opérateurs des chaînes de valeur ciblées.', '[{"type": "paragraph", "children": [{"text": "Consultez les critères, les pièces requises et le calendrier de soumission.", "type": "text"}]}]', '2026-05-01', '2026-06-15', '2026-05-06 23:54:40.687', '2026-05-06 23:54:40.687', '2026-05-06 23:54:40.687', NULL, NULL, NULL, NULL);
INSERT INTO public.call_for_proposals (id, document_id, title, slug, summary, content, opening_date, deadline_date, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, call_status) VALUES (2, 'o62x0clwp7998wst2fazykm2', 'D’AVIS D’APPEL A PROPOSITIONS DE PROJETS, PHASE PILOTE ', 'appel-cohorte-1-2026', 'Appel destiné aux opérateurs éligibles des chaînes de valeur ciblées par PRETE', '[{"type": "paragraph", "children": [{"text": "Le Gouvernement de la République du Burundi avec l''appui technique et financier de la Banque mondiale, a initié le Projet pour l''Emploi et la Transformation Économique (PRETE NYUNGANIRA) pour soutenir le Plan National de Développement (PND) 2018-2027 et mettre en œuvre certaines des recommandations issues du Diagnostic du secteur privé (CPSD) conduit avec l''appui de la Banque mondiale et la Société Financière Internationale. Le Projet s''inscrit dans une optique d''alignement avec les priorités du Gouvernement telles que formulées dans le PND révisé 2023-2028 et la vision Burundi 2040-2060.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "L''objectif de développement du projet PRETE est d''améliorer l''accès au financement des MPME en particulier pour les MPME détenues par des femmes et des réfugiés, et d''augmenter la création d''emplois par ces mêmes MPME. Les principaux bénéficiaires du projet sont les MPME, les fournisseurs d''infrastructures productives, les institutions financières, y compris les Institutions de Microfinance (IMF), les Institutions Gouvernementales et Organisations du secteur privé. ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Le projet PRETE s''appuie sur 5 composantes à savoir (1) l’accès des MPME aux marchés et développement de chaînes de valeur ; (2) Inclusion financière et accès durable au financement pour les MPME ; (3) Environnement des affaires favorable et durable et soutien au climat d''investissement ; (4) Gestion du projet ; et (5) Composante contingente d''intervention d''urgence (CERC). ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Dans le cadre de la mise en œuvre de la sous-composante 1.1 relative à l’amélioration de l’accès des MPME aux infrastructures productives durables y compris aux infrastructures numériques, il est prévu un appui aux opérateurs privés d’infrastructures productives par l’octroi des subventions de contrepartie et la fourniture d’une assistance technique. ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "C’est dans ce contexte que le projet PRETE lance un avis d’appel à propositions de projets pour la mise en œuvre du mécanisme des subventions de contrepartie.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les candidats à cet appel sont des entités se trouvant dans les catégories suivantes : les entreprises, les coopératives, les associations, les organisations non gouvernementales (ONG) et les fournisseurs de services numériques aux MPME (tels que des plateformes numériques, y compris le commerce électronique) et œuvrant dans les différents maillons des chaines de valeur fruits tropicaux, volaille, pisciculture, lait et industrie minière. ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les candidats intéressés par le présent appel peuvent constituer le dossier de candidature comprenant : ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "i.\tLettre de transmission du dossier adressée à Madame le Coordonnateur National du projet PRETE ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "ii.\tFormulaire type d’appel à projet dûment renseigné (annexe aux TDR) ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "iii.\tCopie des actes de création de la structure (Registre de commerce et NIF) ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "iv.\tAttestation fiscale encore valable", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "v.\tAttestation environnementale ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "vi.\tExtraits bancaires pour une période de 6 mois ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "vii.\tEtats financiers de trois ans (3 dernières années) ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "viii.\tPlan d’affaires simplifié (annexe aux TDR) ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "ix.\tListe d’au moins 10 bénéficiaires potentiels des services de l’infrastructure (PME, associations, coopératives avec 50% des femmes) ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "x.\tCV du promoteur de l’infrastructure et de 2 employés clés (si existant) et leurs extraits du casier judiciaire", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "xi.\tEngagement formel signé du gestionnaire de l’infrastructure au cofinancement (format annexé aux TDR)", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "xii.\tEngagement formel signé du gestionnaire de l’infrastructure à respecter les conditions de la subvention (format annexé aux TDR)", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "xiii.\tTout autre document utile pour la bonne analyse des dossiers ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "La soumission des candidatures se fait en ligne via l’adresse : ………….", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les dossiers sont recevables tous les jours ouvrables en ligne jusqu’au 15 mai2026 à 23 h 59 mn au plus tard. Les dossiers physiques sont recevables jusqu’au 15 mai 2026 au plus tard 17h30 au projet PRETE.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Pour tout complément  d’informations, veuillez consulter le site web …………..ou vous adresser à la mission de gestion des Subventions de Contrepartie  au  projet PRETE (Groupement EKVITA-CECODDA –LATTANZIO) bureau du Cabinet CECODDA sise en province de Bujumbura, commune Mukaza ,Zone Rohero, Boulevard du Peuple Murundi,Immeuble UCAR-1er étage ; Tél. : +257 79 222300/ 62867143 / 72036630 ou envoyer un courriel à prete_renseignements@suco.com  ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les termes de référence pour cet appel à propositions de projet sont consultés  sur la plateforme dédiée à la mission des subventions de contrepartie www.suco-prete.bi", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Et au site web du projet PRETE, https://www.prete.bi  ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "\t\t\t\t\t\t\tFait à Bujumbura, le 09 avril 2026", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "\t\t\t\t\t\t\tCoordinatrice du Projet PRETE ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "\t\t\t\t\t\t\tMme NZEYIMANA Béatrice ", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}]', '2026-05-01', '2026-06-15', '2026-05-07 01:30:55.095', '2026-05-07 01:44:51.527', NULL, 1, 1, NULL, 'open');
