INSERT INTO public.candidature_guides (id, document_id, kicker, title, intro, sections, primary_cta_label, primary_cta_url, created_at, updated_at, published_at, created_by_id, updated_by_id, locale) VALUES (1, 'g41kz6y1xsf0oiwrv1yib6ph', 'Candidature', 'Préparer votre demande de subvention', 'Avant de remplir le formulaire, vérifiez les conditions, les documents attendus et les appels ouverts.', '[{"text": "Les entreprises, coopératives, associations, ONG, fournisseurs de services numériques et plateformes liées aux chaînes de valeur prioritaires peuvent préparer un dossier si elles répondent aux critères de l’appel.", "title": "Qui peut candidater ?"}, {"text": "Le candidat doit être actif dans une chaîne de valeur prioritaire, justifier son expérience, proposer un investissement productif viable et mobiliser une contrepartie selon les règles de l’appel.", "title": "Conditions d’éligibilité"}, {"text": "Le mécanisme soutient les infrastructures productives matérielles ou immatérielles : équipements, chaîne du froid, transformation, qualité, traçabilité, services techniques, formation ou dispositifs de marché.", "title": "Ce que finance PRETE SUBCO"}, {"text": "Préparez les documents d’existence légale, les preuves d’activité, les justificatifs d’actifs, les contrats ou bons de commande, les éléments financiers et tout document utile au projet.", "title": "Documents à préparer"}, {"text": "Les dossiers sont soumis en ligne, contrôlés pour complétude, analysés selon les critères administratifs et techniques, puis examinés par les instances prévues par le dispositif.", "title": "Processus de sélection"}]', 'Déposer une candidature', '/candidature/deposer', '2026-05-08 14:28:04.673', '2026-05-08 14:28:04.673', '2026-05-08 14:28:04.673', NULL, NULL, NULL);


