INSERT INTO public.success_stories (id, document_id, title, slug, operator_name, summary, story, impact_metrics, created_at, updated_at, published_at, created_by_id, updated_by_id, locale) VALUES (1, 'xz6budm6u82y1ji7d7inyzp6', 'Opérateur fruits tropicaux - montée en capacité', 'operateur-fruits-tropicaux', 'Cooperative Fruits Tropicaux', 'Mise en place d’une infrastructure partagée au service des MPME locales.', '[{"type": "paragraph", "children": [{"text": "Le projet a renforcé la transformation locale et l’accès au marché.", "type": "text"}]}]', '{"emplois": 24, "beneficiaires": 120}', '2026-05-06 23:54:40.699', '2026-05-06 23:54:40.699', '2026-05-06 23:54:40.699', NULL, NULL, NULL);


