INSERT INTO public.value_chains (id, document_id, name, slug, short_intro, full_content, priority_order, is_featured_home, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, photo_hint) VALUES (9, 'z7hvinn1qdgikettbvd3zv3e', 'Lait', 'lait', 'Structurer la collecte, la chaîne du froid, la transformation et la distribution pour améliorer qualité et revenus des acteurs.', '[{"type": "paragraph", "children": [{"text": "Chaîne lait : centres de collecte, équipements froid, transformation et distribution.", "type": "text"}]}]', 2, true, '2026-05-07 22:00:31.287', '2026-05-07 22:30:45.855', NULL, NULL, 1, NULL, 'Centre de collecte de lait avec bidons inox et tank de refroidissement, test qualité en cours.');
