INSERT INTO public.value_chains (id, document_id, name, slug, short_intro, full_content, priority_order, is_featured_home, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, photo_hint) VALUES (11, 'bnncszyl7u70ilmtrwrrdt3a', 'Volaille', 'volaille', 'Soutenir les maillons critiques de transformation, conservation, conditionnement et commercialisation de la filière volaille.', '[{"type": "paragraph", "children": [{"text": "Chaîne volaille : abattage, conservation, transformation et vente structurée.", "type": "text"}]}]', 3, true, '2026-05-07 22:00:31.299', '2026-05-07 22:31:26.199', NULL, NULL, 1, NULL, 'Élevage avicole propre ou abattoir semi-moderne avec opérateurs en tenue d’hygiène.');
INSERT INTO public.value_chains (id, document_id, name, slug, short_intro, full_content, priority_order, is_featured_home, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, photo_hint) VALUES (21, 'bnncszyl7u70ilmtrwrrdt3a', 'Volaille', 'volaille', 'Soutenir les maillons critiques de transformation, conservation, conditionnement et commercialisation de la filière volaille.', '[{"type": "paragraph", "children": [{"text": "Chaîne volaille : abattage, conservation, transformation et vente structurée.", "type": "text"}]}]', 3, true, '2026-05-07 22:00:31.299', '2026-05-07 22:31:26.199', '2026-05-07 22:31:26.208', NULL, 1, NULL, 'Élevage avicole propre ou abattoir semi-moderne avec opérateurs en tenue d’hygiène.');
INSERT INTO public.value_chains (id, document_id, name, slug, short_intro, full_content, priority_order, is_featured_home, created_at, updated_at, published_at, created_by_id, updated_by_id, locale, photo_hint) VALUES (7, 'emboy81jrwmgofify8pwk5ff', 'Fruits tropicaux', 'fruits-tropicaux', 'Renforcer les infrastructures post-récolte, stockage, transformation et accès marché pour limiter les pertes et créer de la valeur.', '[{"type": "paragraph", "children": [{"bold": true, "text": "Positionnement pour la plateforme", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "La chaîne de valeur des fruits tropicaux est l’une des filières les plus porteuses pour le Burundi. Elle s’appuie sur une production diversifiée, présente dans plusieurs provinces, avec des produits comme la banane, l’avocat, la mangue, l’ananas, le fruit de la passion et la papaye. Son potentiel se situe dans la réduction des pertes, l’amélioration de la qualité, la transformation locale et l’accès à des marchés mieux structurés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"bold": true, "text": "Maillons à mettre en avant", "type": "text"}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "collecte et agrégation ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "tri, calibrage et contrôle qualité ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "stockage temporaire et chaîne du froid ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "conditionnement et emballage ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "transformation en produits à plus longue durée de conservation ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "commercialisation vers marchés urbains, institutionnels, régionaux ou d’exportation ;", "type": "text"}]}]}, {"type": "list", "format": "unordered", "children": [{"type": "list-item", "children": [{"text": "information de marché et traçabilité numérique.", "type": "text"}]}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"bold": true, "text": "Contraintes spécifiques", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "La filière souffre d’une production fragmentée, ce qui rend difficile la constitution de volumes réguliers pour les acheteurs ou transformateurs. Les pratiques post-récolte restent faibles : récolte à maturité non optimale, manipulation inadéquate, transport dans des contenants inadaptés, exposition à la chaleur et stockage insuffisant.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "L’absence de chaîne du froid réduit la durée de conservation, provoque des pertes rapides et limite l’accès aux marchés urbains ou export. La transformation locale reste insuffisante, alors qu’elle pourrait absorber les surplus saisonniers. Le conditionnement, l’emballage, la certification, la traçabilité et l’information de marché restent également faibles.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"bold": true, "text": "Opportunités économiques", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les opportunités les plus fortes concernent le marché national urbain, les hôtels, restaurants, supermarchés, institutions et acheteurs structurés. La transformation peut diversifier les débouchés : jus pasteurisés, nectars, pulpes congelées, fruits séchés, confitures, purées, farine de banane, huile d’avocat et ingrédients semi-transformés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "L’avocat constitue une opportunité spécifique d’exportation, sous réserve de maîtriser la variété, la maturité, le calibrage, le conditionnement, la chaîne du froid, la certification et l’organisation des volumes.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"bold": true, "text": "Infrastructures productives possibles", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Cette liste est indicative et non exhaustive. Elle doit inspirer les opérateurs sans fermer la porte à d’autres infrastructures alignées avec PRETE.", "type": "text"}]}, {"type": "list", "format": "ordered", "children": [{"type": "list-item", "children": [{"text": "Centre de collecte, tri et agrégation de fruits", "type": "text"}]}]}, {"type": "paragraph", "children": [{"text": "Rôle :", "type": "text", "underline": true}, {"text": " regrouper les volumes, peser, enregistrer les producteurs, réaliser un premier tri, organiser les lots et préparer les expéditions.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés :", "type": "text", "underline": true}, {"text": " fragmentation de l’offre, pertes post-récolte, absence de traçabilité, faible pouvoir de négociation des producteurs.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Bénéficiaires :", "type": "text", "underline": true}, {"text": " petits producteurs, coopératives, femmes entrepreneures, jeunes collecteurs, transformateurs, commerçants structurés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Conditions de viabilité : ", "type": "text", "underline": true}, {"text": "bassin de production suffisant, localisation proche des producteurs, contrats ou accords d’approvisionnement, gestion transparente, lien avec acheteurs ou transformateurs.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : fruits en caisses, opérateurs en train de trier et peser, espace semi-industriel simple et propre.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Station de conditionnement pour fruits frais", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : laver, trier finement, calibrer, emballer, étiqueter, contrôler la qualité et préparer les fruits pour les marchés formels.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : qualité hétérogène, absence de standardisation, accès limité aux supermarchés, hôtels et acheteurs export.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Produits concernés : avocat, mangue, ananas, papaye, fruit de la passion et autres fruits frais.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : ligne de calibrage ou tables de tri avec fruits propres, emballages, caisses ou cartons.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Chambre froide solaire ou hybride", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : préserver la qualité des fruits périssables et allonger leur durée de conservation.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : ventes précipitées, pertes rapides, volatilité des prix, impossibilité de servir régulièrement les marchés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Services possibles : stockage réfrigéré, pré-refroidissement, conservation temporaire, gestion des stocks, appui à la distribution.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Conditions de viabilité : étude énergétique, volumes réguliers, tarification réaliste, maintenance, formation des utilisateurs.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : chambre froide, caisses de fruits, panneau solaire ou équipement frigorifique visible.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Unité de transformation multi-fruits", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : transformer les surplus ou fruits de qualité commerciale secondaire en produits à plus forte valeur ajoutée.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Produits possibles : jus, pulpes, confitures, fruits séchés, purées, nectars, produits semi-transformés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : pertes saisonnières, faible valeur ajoutée locale, dépendance au marché frais.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Conditions de viabilité : approvisionnement sécurisé, normes d’hygiène, emballage adapté, débouchés commerciaux, fonds de roulement.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : ligne de jus, fruits découpés, bouteilles, séchoir ou atelier propre de transformation.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Unité de transformation d’avocat", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : valoriser l’avocat au-delà du marché frais.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Produits possibles : huile d’avocat, pulpe, produits cosmétiques dérivés, avocat conditionné pour marché spécialisé.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : valorisation insuffisante d’un produit à fort potentiel, accès limité aux marchés spécialisés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : avocats triés, extraction d’huile, flacons ou conditionnement de produit dérivé.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Unité ou service d’emballage", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : fournir des caisses, cartons, bouteilles, sachets, étiquettes et emballages adaptés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : pertes, faible attractivité commerciale, non-conformité aux exigences des acheteurs.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Particularité : cette infrastructure peut aussi servir d’autres chaînes de valeur.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : emballages alimentaires, cartons imprimés, caisses propres, étiquetage.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Plateforme numérique d’information de marché", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Rôle : diffuser les prix, suivre les volumes disponibles, identifier les producteurs, organiser la mise en relation et améliorer la traçabilité.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Besoins adressés : faible information de marché, ventes dispersées, difficulté de planification.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Condition critique : être reliée à des opérateurs physiques et à des services concrets, pas seulement à une application isolée.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Photo suggérée : agent utilisant une tablette ou téléphone dans un centre de collecte avec producteurs ou fruits visibles.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Modèle économique pertinent", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Le modèle le plus pertinent est celui d’un opérateur-agrégateur : entreprise privée, coopérative professionnalisée, union de coopératives, transformateur, opérateur logistique ou plateforme commerciale. L’opérateur contractualise avec les producteurs, organise la collecte, gère l’infrastructure, contrôle la qualité et vend à des acheteurs structurés.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Les revenus peuvent provenir de frais de collecte, frais de stockage, services de conditionnement, marge commerciale, vente de produits transformés, transport, location d’espace, prestations qualité ou abonnements numériques.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Alignement spécifique avec PRETE", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "La subvention de contrepartie peut soutenir les équipements de tri, chambres froides, lignes de transformation, véhicules adaptés, équipements d’emballage, outils numériques et dispositifs qualité. Le projet doit démontrer un apport propre réel, des volumes disponibles, un business plan crédible, des débouchés, un plan d’inclusion, un plan environnemental et social et une stratégie de maintenance.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Impacts attendus", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "réduction des pertes post-récolte ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "augmentation de la valeur ajoutée locale ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "amélioration des prix producteurs ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "développement de produits transformés ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "accès à de nouveaux marchés ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "création d’emplois dans la collecte, le tri, la transformation, la logistique et le numérique ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "inclusion des femmes et des jeunes ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "meilleure valorisation des surplus saisonniers ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "recours possible au froid solaire ou hybride.", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "Risques à surveiller", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "volumes insuffisants ou irréguliers ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "coûts énergétiques élevés ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "faible qualité des fruits collectés ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "débouchés commerciaux insuffisants ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "gouvernance faible de l’opérateur ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "exclusion des petits producteurs ;", "type": "text"}]}, {"type": "paragraph", "children": [{"text": "non-respect des normes sanitaires.", "type": "text"}]}]', 1, true, '2026-05-07 22:00:31.27', '2026-05-08 00:51:50.586', NULL, NULL, 1, NULL, 'Producteurs manipulant mangues, ananas, avocats ou bananes dans un centre de collecte avec tri visible.');


